  // Check Lo <= Hi for a valid range
  if (!Lo->sle(*Hi))
    return nullptr;

  // We want to check Lo <= X <= Hi
  // This is equivalent to: 0 <= X - Lo <= Hi - Lo
  // Which is: (X - Lo) ult (Hi - Lo + 1) when treated as unsigned
  //
  // To compute X - Lo, we add -Lo (which is positive if Lo is negative)
  // Range size = Hi - Lo + 1
  APInt RangeSize = *Hi - *Lo + 1;
  APInt NegLo = -*Lo;

  // Check that the range fits in the bitwidth (RangeSize should be representable)
  unsigned BitWidth = X->getType()->getScalarSizeInBits();
  if (RangeSize.getBitWidth() > BitWidth)
    return nullptr;

  // Truncate to the actual bit width
  RangeSize = RangeSize.trunc(BitWidth);
  NegLo = NegLo.trunc(BitWidth);

  // Create X + (-Lo)
  Value *Offset = ConstantInt::get(X->getType(), NegLo);
  Value *AdjustedX = Builder.CreateAdd(X, Offset);

  // Create (X + (-Lo)) ult RangeSize
  Value *RangeSizeConst = ConstantInt::get(X->getType(), RangeSize);
  return new ICmpInst(ICmpInst::ICMP_ULT, AdjustedX, RangeSizeConst);
